**PRODUCTION PATTERN WITH CERTIFICATE PINNING**:

```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Net.Http;
using System.Net.Security;
using System.Security.Authentication;
using System.Security.Cryptography;
using System.Security.Cryptography.X509Certificates;
using System.Text;
using System.Text.Json;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace PaymentService.Security
{
    public class TlsConfiguration
    {
        public string[] PinnedPublicKeyHashes { get; set; } = Array.Empty<string>();
        public string[] BackupPublicKeyHashes { get; set; } = Array.Empty<string>();
        public string Endpoint { get; set; } = string.Empty;
        public int TimeoutSeconds { get; set; } = 30;
        public bool EnablePinning { get; set; } = true;
        public int MaxRetries { get; set; } = 3;
    }

    public class CertificatePinningHandler : HttpClientHandler
    {
        private readonly HashSet<string> _pinnedHashes;
        private readonly ILogger _logger;
        private readonly bool _pinningEnabled;

        public CertificatePinningHandler(
            IOptions<TlsConfiguration> config,
            ILogger<CertificatePinningHandler> logger)
        {
            _logger = logger;
            _pinningEnabled = config.Value.EnablePinning;

            // Combine primary and backup pins for rotation support
            _pinnedHashes = new HashSet<string>(
                config.Value.PinnedPublicKeyHashes
                    .Concat(config.Value.BackupPublicKeyHashes),
                StringComparer.OrdinalIgnoreCase);

            // SECURE: Enforce TLS 1.2+ only
            SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13;

            // SECURE: Check certificate revocation
            CheckCertificateRevocationList = true;

            // SECURE: Custom validation with pinning
            ServerCertificateCustomValidationCallback = ValidateCertificateWithPinning;
        }

        private bool ValidateCertificateWithPinning(
            HttpRequestMessage request,
            X509Certificate2? certificate,
            X509Chain? chain,
            SslPolicyErrors sslErrors)
        {
            // Step 1: Standard certificate validation
            if (sslErrors != SslPolicyErrors.None)
            {
                _logger.LogError(
                    "TLS validation failed for {Host}: {Errors}",
                    request.RequestUri?.Host, sslErrors);
                return false;
            }

            if (certificate == null)
            {
                _logger.LogError("No certificate presented by server");
                return false;
            }

            // Step 2: Certificate pinning (if enabled)
            if (_pinningEnabled)
            {
                return ValidatePin(certificate, chain, request.RequestUri?.Host);
            }

            return true;
        }

        private bool ValidatePin(X509Certificate2 certificate, X509Chain? chain, string? host)
        {
            // Pin against the leaf certificate's public key
            var leafPinHash = GetPublicKeyHash(certificate);
            if (_pinnedHashes.Contains(leafPinHash))
            {
                _logger.LogDebug("Certificate pinning succeeded for leaf cert: {Host}", host);
                return true;
            }

            // Also check intermediate certificates for backup pin support
            if (chain?.ChainElements != null)
            {
                foreach (var element in chain.ChainElements)
                {
                    var intermediateHash = GetPublicKeyHash(element.Certificate);
                    if (_pinnedHashes.Contains(intermediateHash))
                    {
                        _logger.LogDebug(
                            "Certificate pinning succeeded for intermediate cert: {Host}", host);
                        return true;
                    }
                }
            }

            _logger.LogCritical(
                "Certificate pinning FAILED for {Host}. Hash: {Hash}",
                host, leafPinHash);

            // Alert security team
            AlertSecurityTeam(host, leafPinHash);
            return false;
        }

        private static string GetPublicKeyHash(X509Certificate2 certificate)
        {
            using var rsa = certificate.GetRSAPublicKey();
            using var ecdsa = certificate.GetECDsaPublicKey();

            byte[] publicKeyBytes;
            if (rsa != null)
            {
                publicKeyBytes = rsa.ExportSubjectPublicKeyInfo();
            }
            else if (ecdsa != null)
            {
                publicKeyBytes = ecdsa.ExportSubjectPublicKeyInfo();
            }
            else
            {
                throw new CryptographicException("Unsupported public key algorithm");
            }

            using var sha256 = SHA256.Create();
            var hash = sha256.ComputeHash(publicKeyBytes);
            return "sha256/" + Convert.ToBase64String(hash);
        }

        private void AlertSecurityTeam(string? host, string hash)
        {
            // Integration with SIEM/alerting system
            _logger.LogCritical(
                "SECURITY ALERT: Potential MITM attack detected. Host: {Host}, UnexpectedHash: {Hash}",
                host, hash);
        }
    }

    public class SecurePaymentService : IDisposable
    {
        private readonly HttpClient _httpClient;
        private readonly ILogger<SecurePaymentService> _logger;
        private readonly TlsConfiguration _config;
        private readonly SemaphoreSlim _rateLimiter;

        public SecurePaymentService(
            IOptions<TlsConfiguration> config,
            ILogger<SecurePaymentService> logger,
            ILogger<CertificatePinningHandler> handlerLogger)
        {
            _config = config.Value;
            _logger = logger;
            _rateLimiter = new SemaphoreSlim(100, 100);

            var handler = new CertificatePinningHandler(config, handlerLogger);
            _httpClient = new HttpClient(handler)
            {
                Timeout = TimeSpan.FromSeconds(_config.TimeoutSeconds),
                BaseAddress = new Uri(_config.Endpoint)
            };

            // Add security headers
            _httpClient.DefaultRequestHeaders.Add("User-Agent", "SecurePaymentClient/2.0");
        }

        public async Task<PaymentResult> ProcessPaymentAsync(
            PaymentRequest request,
            CancellationToken cancellationToken = default)
        {
            // Rate limiting
            if (!await _rateLimiter.WaitAsync(TimeSpan.FromSeconds(5), cancellationToken))
            {
                throw new InvalidOperationException("Rate limit exceeded");
            }

            try
            {
                // Retry with exponential backoff
                for (int attempt = 1; attempt <= _config.MaxRetries; attempt++)
                {
                    try
                    {
                        return await ExecutePaymentRequest(request, cancellationToken);
                    }
                    catch (HttpRequestException ex) when (attempt < _config.MaxRetries)
                    {
                        var delay = TimeSpan.FromSeconds(Math.Pow(2, attempt));
                        _logger.LogWarning(
                            "Payment request failed (attempt {Attempt}), retrying in {Delay}s: {Error}",
                            attempt, delay.TotalSeconds, ex.Message);
                        await Task.Delay(delay, cancellationToken);
                    }
                }

                throw new InvalidOperationException("Payment processing failed after max retries");
            }
            finally
            {
                _rateLimiter.Release();
            }
        }

        private async Task<PaymentResult> ExecutePaymentRequest(
            PaymentRequest request,
            CancellationToken cancellationToken)
        {
            var jsonContent = JsonSerializer.Serialize(request);
            using var content = new StringContent(jsonContent, Encoding.UTF8, "application/json");

            var response = await _httpClient.PostAsync(
                "transactions", content, cancellationToken);

            // Log TLS details for audit
            _logger.LogInformation(
                "Payment request completed. StatusCode: {StatusCode}",
                response.StatusCode);

            response.EnsureSuccessStatusCode();

            var responseBody = await response.Content.ReadAsStringAsync(cancellationToken);
            return JsonSerializer.Deserialize<PaymentResult>(responseBody)
                ?? throw new InvalidOperationException("Invalid response from payment processor");
        }

        public void Dispose()
        {
            _httpClient?.Dispose();
            _rateLimiter?.Dispose();
        }
    }

    public record PaymentRequest(string CardToken, decimal Amount, string Currency);
    public record PaymentResult(string TransactionId, string Status, DateTime Timestamp);
}
