**Why This Is Dangerous**:
- All credentials (username, password, API keys) transmitted in plaintext
- Authentication tokens can be intercepted and replayed
- Attackers on the network can perform MITM attacks silently
- Internal network traffic is often assumed safe but isn't (lateral movement)
- No integrity verification - data can be modified in transit

**SECURE VERSION**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/tls"
	"crypto/x509"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"time"
)

type UserCredentials struct {
	Username string `json:"username"`
	Password string `json:"password"`
	APIKey   string `json:"api_key"`
}

type AuthResponse struct {
	Token   string `json:"token"`
	UserID  int    `json:"user_id"`
	IsAdmin bool   `json:"is_admin"`
}

// SecureHTTPClient creates an HTTP client with proper TLS configuration
func SecureHTTPClient() (*http.Client, error) {
	// Load CA certificate pool for verifying server certificates
	caCert, err := os.ReadFile("/etc/ssl/certs/internal-ca.crt")
	if err != nil {
		return nil, fmt.Errorf("failed to load CA cert: %w", err)
	}

	caCertPool := x509.NewCertPool()
	if !caCertPool.AppendCertsFromPEM(caCert) {
		return nil, fmt.Errorf("failed to parse CA cert")
	}

	tlsConfig := &tls.Config{
		RootCAs:            caCertPool,
		MinVersion:         tls.VersionTLS13,  // Enforce TLS 1.3
		InsecureSkipVerify: false,             // NEVER set to true in production
		CipherSuites: []uint16{
			tls.TLS_AES_256_GCM_SHA384,
			tls.TLS_CHACHA20_POLY1305_SHA256,
		},
	}

	transport := &http.Transport{
		TLSClientConfig:     tlsConfig,
		ForceAttemptHTTP2:   true,
		MaxIdleConns:        100,
		IdleConnTimeout:     90 * time.Second,
		TLSHandshakeTimeout: 10 * time.Second,
	}

	return &http.Client{
		Transport: transport,
		Timeout:   30 * time.Second,
	}, nil
}

func authenticateUserSecure(ctx context.Context, creds UserCredentials) (*AuthResponse, error) {
	client, err := SecureHTTPClient()
	if err != nil {
		return nil, fmt.Errorf("failed to create secure client: %w", err)
	}

	// SECURE: Always use HTTPS
	authURL := "https://auth-service.internal:8443/api/authenticate"

	jsonData, err := json.Marshal(creds)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal credentials: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, "POST", authURL, bytes.NewBuffer(jsonData))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("authentication request failed: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("authentication failed with status: %d", resp.StatusCode)
	}

	var authResp AuthResponse
	if err := json.NewDecoder(resp.Body).Decode(&authResp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	log.Printf("User %d authenticated successfully", authResp.UserID)
	return &authResp, nil
}
```

**Key Security Controls**:
- **TLS 1.3 enforced**: Uses only the latest TLS version with strong cipher suites
- **Certificate verification**: Validates server certificates against trusted CA pool
- **InsecureSkipVerify is false**: Never bypasses certificate validation
- **Proper timeout handling**: Prevents indefinite hangs and resource exhaustion
- **Context propagation**: Allows request cancellation and deadline management

Mutual TLS (mTLS) is essential for zero-trust microservices architectures where both client and server authenticate each other using certificates. This prevents unauthorized services from communicating even within your internal network.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/tls"
	"crypto/x509"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"sync"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
)

// Metrics for monitoring TLS connections
var (
	tlsHandshakeErrors = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "mtls_handshake_errors_total",
			Help: "Total number of mTLS handshake errors",
		},
		[]string{"service", "error_type"},
	)

	tlsConnectionsActive = promauto.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "mtls_connections_active",
			Help: "Number of active mTLS connections",
		},
		[]string{"service"},
	)

	requestDuration = promauto.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "service_request_duration_seconds",
			Help:    "Request duration in seconds",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"service", "method", "status"},
	)
)

// MTLSConfig holds the configuration for mutual TLS
type MTLSConfig struct {
	CACertPath     string
	ClientCertPath string
	ClientKeyPath  string
	MinTLSVersion  uint16
	ServiceName    string
}

// SecureServiceClient manages secure connections to internal services
type SecureServiceClient struct {
	client      *http.Client
	baseURL     string
	serviceName string
	mu          sync.RWMutex
	tlsConfig   *tls.Config
}

// NewSecureServiceClient creates a client with mTLS enabled
func NewSecureServiceClient(cfg MTLSConfig, baseURL string) (*SecureServiceClient, error) {
	// Load CA certificate for verifying server
	caCert, err := os.ReadFile(cfg.CACertPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read CA cert: %w", err)
	}

	caCertPool := x509.NewCertPool()
	if !caCertPool.AppendCertsFromPEM(caCert) {
		return nil, fmt.Errorf("failed to parse CA cert")
	}

	// Load client certificate and key for client authentication
	clientCert, err := tls.LoadX509KeyPair(cfg.ClientCertPath, cfg.ClientKeyPath)
	if err != nil {
		return nil, fmt.Errorf("failed to load client cert/key: %w", err)
	}

	// Verify client certificate is valid
	if len(clientCert.Certificate) == 0 {
		return nil, fmt.Errorf("client certificate is empty")
	}

	parsedCert, err := x509.ParseCertificate(clientCert.Certificate[0])
	if err != nil {
		return nil, fmt.Errorf("failed to parse client cert: %w", err)
	}

	// Check certificate expiration
	if time.Now().After(parsedCert.NotAfter) {
		return nil, fmt.Errorf("client certificate has expired")
	}

	if time.Now().Before(parsedCert.NotBefore) {
		return nil, fmt.Errorf("client certificate is not yet valid")
	}

	// Warn if certificate expires soon (within 30 days)
	if time.Until(parsedCert.NotAfter) < 30*24*time.Hour {
		log.Printf("WARNING: Client certificate expires in %v", time.Until(parsedCert.NotAfter))
	}

	tlsConfig := &tls.Config{
		RootCAs:            caCertPool,
		Certificates:       []tls.Certificate{clientCert},
		MinVersion:         tls.VersionTLS13,
		InsecureSkipVerify: false,
		// Strict cipher suites for TLS 1.3
		CipherSuites: []uint16{
			tls.TLS_AES_256_GCM_SHA384,
			tls.TLS_CHACHA20_POLY1305_SHA256,
			tls.TLS_AES_128_GCM_SHA256,
		},
		// Verify peer certificate
		VerifyPeerCertificate: func(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
			if len(verifiedChains) == 0 || len(verifiedChains[0]) == 0 {
				return fmt.Errorf("no verified certificate chain")
			}

			peerCert := verifiedChains[0][0]
			log.Printf("Connected to server with cert CN=%s, expires=%v",
				peerCert.Subject.CommonName, peerCert.NotAfter)
			return nil
		},
	}

	transport := &http.Transport{
		TLSClientConfig:       tlsConfig,
		ForceAttemptHTTP2:     true,
		MaxIdleConns:          100,
		MaxIdleConnsPerHost:   10,
		IdleConnTimeout:       90 * time.Second,
		TLSHandshakeTimeout:   10 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
	}

	return &SecureServiceClient{
		client: &http.Client{
			Transport: transport,
			Timeout:   30 * time.Second,
		},
		baseURL:     baseURL,
		serviceName: cfg.ServiceName,
		tlsConfig:   tlsConfig,
	}, nil
}

// DoRequest performs a secure request with metrics and logging
func (c *SecureServiceClient) DoRequest(ctx context.Context, method, path string, body interface{}) ([]byte, error) {
	start := time.Now()
	status := "error"

	defer func() {
		requestDuration.WithLabelValues(c.serviceName, method, status).Observe(time.Since(start).Seconds())
	}()

	var bodyReader io.Reader
	if body != nil {
		jsonData, err := json.Marshal(body)
		if err != nil {
			return nil, fmt.Errorf("failed to marshal body: %w", err)
		}
		bodyReader = bytes.NewBuffer(jsonData)
	}

	url := fmt.Sprintf("%s%s", c.baseURL, path)
	req, err := http.NewRequestWithContext(ctx, method, url, bodyReader)
	if err != nil {
		tlsHandshakeErrors.WithLabelValues(c.serviceName, "request_creation").Inc()
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	if body != nil {
		req.Header.Set("Content-Type", "application/json")
	}

	// Add request ID for tracing
	requestID := fmt.Sprintf("%d", time.Now().UnixNano())
	req.Header.Set("X-Request-ID", requestID)
	req.Header.Set("X-Service-Name", c.serviceName)

	tlsConnectionsActive.WithLabelValues(c.serviceName).Inc()
	defer tlsConnectionsActive.WithLabelValues(c.serviceName).Dec()

	resp, err := c.client.Do(req)
	if err != nil {
		tlsHandshakeErrors.WithLabelValues(c.serviceName, "connection").Inc()
		log.Printf("ERROR [%s] mTLS request to %s failed: %v", requestID, c.serviceName, err)
		return nil, fmt.Errorf("request failed: %w", err)
	}
	defer resp.Body.Close()

	status = fmt.Sprintf("%d", resp.StatusCode)

	if resp.StatusCode >= 400 {
		bodyBytes, _ := io.ReadAll(resp.Body)
		log.Printf("ERROR [%s] %s %s returned %d: %s", 
			requestID, method, path, resp.StatusCode, string(bodyBytes))
		return nil, fmt.Errorf("request returned status %d", resp.StatusCode)
	}

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read response: %w", err)
	}

	log.Printf("INFO [%s] %s %s completed in %v", 
		requestID, method, path, time.Since(start))

	return data, nil
}

// Server-side mTLS configuration
func CreateMTLSServer(cfg MTLSConfig) (*http.Server, error) {
	// Load CA cert for verifying client certificates
	caCert, err := os.ReadFile(cfg.CACertPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read CA cert: %w", err)
	}

	caCertPool := x509.NewCertPool()
	if !caCertPool.AppendCertsFromPEM(caCert) {
		return nil, fmt.Errorf("failed to parse CA cert")
	}

	// Load server certificate
	serverCert, err := tls.LoadX509KeyPair(cfg.ClientCertPath, cfg.ClientKeyPath)
	if err != nil {
		return nil, fmt.Errorf("failed to load server cert: %w", err)
	}

	tlsConfig := &tls.Config{
		ClientCAs:                caCertPool,
		Certificates:             []tls.Certificate{serverCert},
		ClientAuth:               tls.RequireAndVerifyClientCert, // Enforce mTLS
		MinVersion:               tls.VersionTLS13,
		PreferServerCipherSuites: true,
		CipherSuites: []uint16{
			tls.TLS_AES_256_GCM_SHA384,
			tls.TLS_CHACHA20_POLY1305_SHA256,
		},
		// Custom verification for client certificates
		VerifyPeerCertificate: func(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
			if len(verifiedChains) == 0 {
				return fmt.Errorf("no client certificate provided")
			}

			clientCert := verifiedChains[0][0]

			// Log client identity for audit
			log.Printf("AUDIT: Client connected - CN=%s, O=%s, Serial=%s",
				clientCert.Subject.CommonName,
				clientCert.Subject.Organization,
				clientCert.SerialNumber.String())

			// Verify certificate is from expected organization
			if len(clientCert.Subject.Organization) == 0 ||
				clientCert.Subject.Organization[0] != "MyCompany Internal Services" {
				return fmt.Errorf("client certificate from unauthorized organization")
			}

			return nil
		},
	}

	return &http.Server{
		Addr:         ":8443",
		TLSConfig:    tlsConfig,
		ReadTimeout:  30 * time.Second,
		WriteTimeout: 30 * time.Second,
		IdleTimeout:  120 * time.Second,
	}, nil
}

// Example usage
func main() {
	cfg := MTLSConfig{
		CACertPath:     "/etc/ssl/certs/internal-ca.crt",
		ClientCertPath: "/etc/ssl/certs/service-client.crt",
		ClientKeyPath:  "/etc/ssl/private/service-client.key",
		MinTLSVersion:  tls.VersionTLS13,
		ServiceName:    "user-service",
	}

	client, err := NewSecureServiceClient(cfg, "https://auth-service.internal:8443")
	if err != nil {
		log.Fatalf("Failed to create secure client: %v", err)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	data, err := client.DoRequest(ctx, "GET", "/api/health", nil)
	if err != nil {
		log.Printf("Request failed: %v", err)
		return
	}

	log.Printf("Response: %s", string(data))
}
