                AllowAutoRedirect = false
            };

            _httpClient = new HttpClient(handler)
            {
                Timeout = TimeSpan.FromSeconds(30)
            };

            // SECURE: Set default headers
            _httpClient.DefaultRequestHeaders.Add("Strict-Transport-Security", "max-age=31536000; includeSubDomains");
        }

        private bool ValidateServerCertificate(
            HttpRequestMessage request,
            X509Certificate2 certificate,
            X509Chain chain,
            SslPolicyErrors sslPolicyErrors)
        {
            if (sslPolicyErrors == SslPolicyErrors.None)
                return true;

            _logger.LogError("Certificate validation failed: {Errors} for {Host}",
                sslPolicyErrors, request.RequestUri?.Host);
            return false;
        }

        public async Task<string> ProcessPaymentAsync(string cardNumber, string cvv, decimal amount)
        {
            // SECURE: Enforce HTTPS scheme
            var url = "https://payment-gateway.example.com/api/process";

            if (!url.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            {
                throw new InvalidOperationException("Only HTTPS connections are allowed");
            }

            var content = new StringContent(
                System.Text.Json.JsonSerializer.Serialize(new { card = cardNumber, cvv, amount }),
                System.Text.Encoding.UTF8,
                "application/json"
            );

            var response = await _httpClient.PostAsync(url, content);
            response.EnsureSuccessStatusCode();

            _logger.LogInformation("Payment processed successfully");
            return await response.Content.ReadAsStringAsync();
        }

        public void Dispose()
        {
            _httpClient?.Dispose();
        }
    }
}
```

**Key Security Controls**:
- **TLS 1.2+ Enforcement**: Only allows modern, secure TLS protocols - disables SSLv3, TLS 1.0, TLS 1.1 which have known vulnerabilities
- **Certificate Validation**: Custom callback validates server certificates and logs failures - prevents MITM with fake certificates
- **HTTPS-Only**: URL validation ensures only HTTPS connections are made - prevents accidental HTTP downgrades
- **Disabled Auto-Redirect**: Prevents attackers from using 301/302 redirects to downgrade HTTPS to HTTP

Excellent question! Certificate pinning adds an additional layer of protection against compromised Certificate Authorities, while proper environment-specific configuration allows secure development without weakening production security.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.Net.Http;
using System.Net.Security;
using System.Security.Authentication;
using System.Security.Cryptography;
using System.Security.Cryptography.X509Certificates;
using System.Threading.Tasks;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using Polly;
using Polly.Extensions.Http;

namespace PaymentService
{
    public class ProductionSecureHttpClient : IDisposable
    {
        private readonly HttpClient _httpClient;
        private readonly ILogger<ProductionSecureHttpClient> _logger;
        private readonly IConfiguration _configuration;
        private readonly HashSet<string> _pinnedCertificateHashes;
        private readonly bool _isDevelopment;

        public ProductionSecureHttpClient(
            ILogger<ProductionSecureHttpClient> logger,
            IConfiguration configuration)
        {
            _logger = logger;
            _configuration = configuration;
            _isDevelopment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") == "Development";

            // Load pinned certificate hashes from secure configuration
            _pinnedCertificateHashes = new HashSet<string>(
                configuration.GetSection("Security:PinnedCertificates").Get<string[]>() ?? Array.Empty<string>()
            );

            var handler = CreateSecureHandler();
            _httpClient = CreateResilientHttpClient(handler);
        }

        private HttpClientHandler CreateSecureHandler()
        {
            var handler = new HttpClientHandler
            {
                // CRITICAL: Enforce TLS 1.2 and 1.3 only
                SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13,

                // Disable insecure automatic redirect following
                AllowAutoRedirect = false,

                // Maximum connections per server
                MaxConnectionsPerServer = 20
            };

            // Environment-specific certificate validation
            if (_isDevelopment)
            {
                handler.ServerCertificateCustomValidationCallback = ValidateDevelopmentCertificate;
                _logger.LogWarning("Running in DEVELOPMENT mode - using relaxed certificate validation");
            }
            else
            {
                handler.ServerCertificateCustomValidationCallback = ValidateProductionCertificateWithPinning;
            }

            return handler;
        }

        private bool ValidateDevelopmentCertificate(
            HttpRequestMessage request,
            X509Certificate2 certificate,
            X509Chain chain,
            SslPolicyErrors sslPolicyErrors)
        {
            // In development, allow self-signed but still require HTTPS
            if (certificate == null)
            {
                _logger.LogError("No certificate provided by server");
                return false;
            }

            // Check if it's a known development certificate
            var allowedDevHosts = _configuration.GetSection("Development:AllowedSelfSignedHosts")
                .Get<string[]>() ?? Array.Empty<string>();

            var host = request.RequestUri?.Host ?? string.Empty;
            if (allowedDevHosts.Contains(host, StringComparer.OrdinalIgnoreCase))
            {
                _logger.LogDebug("Accepting self-signed certificate for development host: {Host}", host);
                return true;
            }

            // For non-development hosts, still validate properly
            return sslPolicyErrors == SslPolicyErrors.None;
        }

        private bool ValidateProductionCertificateWithPinning(
            HttpRequestMessage request,
            X509Certificate2 certificate,
            X509Chain chain,
            SslPolicyErrors sslPolicyErrors)
        {
            // LAYER 1: Standard certificate validation
            if (sslPolicyErrors != SslPolicyErrors.None)
            {
                _logger.LogError(
                    "Certificate validation failed for {Host}: {Errors}",
                    request.RequestUri?.Host,
                    sslPolicyErrors);
                return false;
            }

            if (certificate == null)
            {
                _logger.LogError("No certificate provided by server");
                return false;
            }

            // LAYER 2: Certificate expiration check
            if (certificate.NotAfter < DateTime.UtcNow)
            {
                _logger.LogError(
                    "Certificate expired on {ExpirationDate} for {Host}",
                    certificate.NotAfter,
                    request.RequestUri?.Host);
                return false;
            }

            // Warn if certificate expires soon (30 days)
            if (certificate.NotAfter < DateTime.UtcNow.AddDays(30))
            {
                _logger.LogWarning(
                    "Certificate for {Host} expires on {ExpirationDate}",
                    request.RequestUri?.Host,
                    certificate.NotAfter);
            }

            // LAYER 3: Certificate pinning (SPKI hash)
            if (_pinnedCertificateHashes.Count > 0)
            {
                var spkiHash = GetSpkiHash(certificate);
                if (!_pinnedCertificateHashes.Contains(spkiHash))
                {
                    _logger.LogCritical(
                        "CERTIFICATE PINNING FAILURE! Host: {Host}, Expected hashes: {Expected}, Actual: {Actual}",
                        request.RequestUri?.Host,
                        string.Join(", ", _pinnedCertificateHashes),
                        spkiHash);

                    // Alert security team
                    AlertSecurityTeam(request.RequestUri?.Host, spkiHash);
                    return false;
                }

                _logger.LogDebug("Certificate pinning validated for {Host}", request.RequestUri?.Host);
            }

            return true;
        }

        private string GetSpkiHash(X509Certificate2 certificate)
        {
            // Calculate SHA-256 hash of the Subject Public Key Info (SPKI)
            using var sha256 = SHA256.Create();
            var spkiBytes = certificate.GetPublicKey();
            var hashBytes = sha256.ComputeHash(spkiBytes);
            return Convert.ToBase64String(hashBytes);
        }

        private void AlertSecurityTeam(string host, string actualHash)
        {
            // Integration with security monitoring
            _logger.LogCritical(
                "SECURITY ALERT: Possible MITM attack detected. Host: {Host}, CertHash: {Hash}",
                host,
                actualHash);
            // Send to SIEM, PagerDuty, etc.
        }

        private HttpClient CreateResilientHttpClient(HttpClientHandler handler)
        {
            // Retry policy with exponential backoff
            var retryPolicy = HttpPolicyExtensions
                .HandleTransientHttpError()
                .WaitAndRetryAsync(3, retryAttempt =>
                    TimeSpan.FromSeconds(Math.Pow(2, retryAttempt)));

            // Circuit breaker
            var circuitBreakerPolicy = HttpPolicyExtensions
                .HandleTransientHttpError()
                .CircuitBreakerAsync(5, TimeSpan.FromMinutes(1));

            var policyHandler = new PolicyHttpMessageHandler(retryPolicy)
            {
                InnerHandler = handler
            };

            var client = new HttpClient(policyHandler)
            {
                Timeout = TimeSpan.FromSeconds(30)
            };

            // Security headers
            client.DefaultRequestHeaders.Add("X-Content-Type-Options", "nosniff");
            client.DefaultRequestHeaders.UserAgent.ParseAdd("SecurePaymentClient/1.0");

            return client;
        }

        public async Task<T> GetSecureAsync<T>(string url) where T : class
        {
            // ENFORCE HTTPS
            if (!url.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
            {
                throw new SecurityException($"Only HTTPS URLs are allowed. Received: {url}");
            }

            try
            {
                var response = await _httpClient.GetAsync(url);
                response.EnsureSuccessStatusCode();

                var content = await response.Content.ReadAsStringAsync();
                return System.Text.Json.JsonSerializer.Deserialize<T>(content);
            }
            catch (HttpRequestException ex) when (ex.InnerException is AuthenticationException)
            {
                _logger.LogError(ex, "TLS/SSL error connecting to {Url}", url);
                throw new SecurityException("Secure connection could not be established", ex);
            }
        }

        public void Dispose()
        {
            _httpClient?.Dispose();
        }
    }

    // Configuration model for appsettings.json
    public class SecurityConfiguration
    {
        public string[] PinnedCertificates { get; set; }
    }
}
